#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);int k;scanf("%d",&k);vector<long long>x(n);for(auto&v:x)scanf("%lld",&v);sort(x.begin(),x.end());if(k>=n){puts("0");return 0;}vector<long long>g;for(int i=1;i<n;i++)g.push_back(x[i]-x[i-1]);sort(g.rbegin(),g.rend());long long sum=0;for(size_t i=k-1;i<g.size();i++)sum+=g[i];printf("%lld\n",sum);}
